#!/usr/bin/env bash
# Generated by scripts/build-installer.sh — do not edit directly.
# Run on a fresh NixOS live ISO to bootstrap the system.
set -euo pipefail

if [ "${EUID:-$(id -u)}" -ne 0 ]; then
  echo "This installer must run as root."
  echo "Use: curl -fL https://raw.githubusercontent.com/zhogoshi/dotfiles/main/install.sh | sudo bash"
  exit 1
fi

DEST=""
USERNAME=""
INIT_PASS=""
KB_LAYOUT="us"
BROWSER_CHOICE=""
PRIMARY_DISK=""
PRIMARY_DEV=""
INSTALL_OK=0
WARNINGS=()
CRITICALS=()
RUN_TMP=""
FAIL_DETAIL_LABELS=()
FAIL_DETAIL_FILES=()

# ── Colors & TUI ─────────────────────────────────────────────────────────────

R='\033[0m'
BOLD='\033[1m'
DIM='\033[2m'
CY='\033[36m'
GR='\033[32m'
YE='\033[33m'
RE='\033[31m'

hide_cursor()  { printf '\033[?25l'; }
show_cursor()  { printf '\033[?25h'; }
clear_screen() { printf '\033[2J\033[H'; }

trap 'show_cursor; rm -rf "${RUN_TMP}" 2>/dev/null || true' EXIT

_abort_install() {
  show_cursor
  clear_screen
  rm -rf "$RUN_TMP" 2>/dev/null || true
  printf '%s\n' "Aborting installation..."
  trap - INT TERM
  exit 130
}
trap '_abort_install' INT TERM

_init_run_tmp() {
  [ -n "$RUN_TMP" ] && return 0
  RUN_TMP="$(mktemp -d "${TMPDIR:-/tmp}/nixsetup.XXXXXX")" || RUN_TMP="${TMPDIR:-/tmp}"
}

_capt() {
  local label="$1" lf
  shift
  _init_run_tmp
  lf="$(mktemp "$RUN_TMP/cap.XXXXXX")"
  if "$@" >"$lf" 2>&1; then
    rm -f "$lf"
    return 0
  fi
  FAIL_DETAIL_LABELS+=("$label")
  FAIL_DETAIL_FILES+=("$lf")
  return 1
}

_review_fail_logs() {
  local rep i
  if [ ${#FAIL_DETAIL_LABELS[@]} -eq 0 ] && [ ${#WARNINGS[@]} -eq 0 ] && [ ${#CRITICALS[@]} -eq 0 ]; then
    return 0
  fi
  _init_run_tmp
  rep="$(mktemp "$RUN_TMP/review.XXXXXX")"
  {
    if [ ${#CRITICALS[@]} -gt 0 ]; then
      printf '%s\n' "=== Errors ==="
      printf '%s\n' "${CRITICALS[@]}"
      printf '\n'
    fi
    if [ ${#WARNINGS[@]} -gt 0 ]; then
      printf '%s\n' "=== Warnings ==="
      printf '%s\n' "${WARNINGS[@]}"
      printf '\n'
    fi
    if [ ${#FAIL_DETAIL_LABELS[@]} -gt 0 ]; then
      printf '%s\n' "=== Last 10 lines per captured command ==="
      for i in "${!FAIL_DETAIL_LABELS[@]}"; do
        printf '\n--- %s ---\n' "${FAIL_DETAIL_LABELS[$i]}"
        tail -n 10 "${FAIL_DETAIL_FILES[$i]}" 2>/dev/null || printf '%s\n' "(no output)"
      done
    fi
  } >"$rep"
  echo ""
  if command -v less >/dev/null 2>&1; then
    echo -e "  ${DIM}Scrollable log: arrows / PgUp·PgDn · q closes${R}"
    less -R "$rep" || true
  else
    cat "$rep"
    read -r -s -p "  Press Enter..." _ || true
  fi
  rm -f "$rep"
}

log() { echo -e "  ${DIM}▸${R} $*"; }
ok()  { echo -e "  ${GR}${BOLD}✓${R} $*"; }
warn(){ echo -e "  ${YE}${BOLD}⚠${R} $*"; WARNINGS+=("$*"); }
err() { echo -e "  ${RE}${BOLD}✗${R} $*"; CRITICALS+=("$*"); }

phase_header() {
  local num="$1" title="$2"
  local iw=46 bar="" mid titlepad i
  clear_screen
  for ((i = 0; i < iw; i++)); do bar+="═"; done
  echo -e ""
  echo -e "  ${CY}${BOLD}╔${bar}╗${R}"
  mid="  NixOS Installer  |  Phase ${num} of 11"
  [ ${#mid} -gt "$iw" ] && mid="${mid:0:iw}"
  printf -v mid '%-*s' "$iw" "$mid"
  echo -e "  ${CY}${BOLD}║${R}${BOLD}${mid}${R}${CY}${BOLD}║${R}"
  echo -e "  ${CY}${BOLD}╠${bar}╣${R}"
  titlepad="  ${title}"
  [ ${#titlepad} -gt "$iw" ] && titlepad="${titlepad:0:iw}"
  printf -v titlepad '%-*s' "$iw" "$titlepad"
  echo -e "  ${CY}${BOLD}║${R}${BOLD}${titlepad}${R}${CY}${BOLD}║${R}"
  echo -e "  ${CY}${BOLD}╚${bar}╝${R}"
  echo -e ""
}

# ── TUI: arrow-key single-select ─────────────────────────────────────────────
tui_select() {
  local -n _result="$1"; shift
  local prompt="$1";     shift
  local items=("$@")
  local cur=0 total=${#items[@]} key esc

  hide_cursor
  echo -e "  ${BOLD}${prompt}${R}"
  echo -e "  ${DIM}(↑↓ select · Enter confirm)${R}"
  echo ""

  _render_list() {
    for i in "${!items[@]}"; do
      if [ "$i" -eq "$cur" ]; then
        echo -e "  ${CY}${BOLD}▶  ${items[$i]}${R}"
      else
        echo -e "     ${DIM}${items[$i]}${R}"
      fi
    done
  }

  printf '\033[s'
  _render_list

  while true; do
    IFS= read -r -s -n1 key
    if [ "$key" = $'\x1b' ]; then
      IFS= read -r -s -n1 esc
      IFS= read -r -s -n1 esc
      case "$esc" in
        A) if [ "$cur" -gt 0 ]; then cur=$(( cur - 1 )); fi ;;
        B) if [ "$cur" -lt $(( total - 1 )) ]; then cur=$(( cur + 1 )); fi ;;
      esac
    elif [ "$key" = "" ]; then
      break
    else
      continue
    fi
    printf '\033[u\033[0J'
    _render_list
  done

  printf '\033[u\033[0J'
  show_cursor
  echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}  ${CY}${items[$cur]}${R}"
  echo ""
  _result="${items[$cur]}"
}

# ── TUI: checkbox multi-select ────────────────────────────────────────────────
tui_checkbox() {
  local -n _checked="$1"; shift
  local prompt="$1";      shift
  local items=("$@")
  local cur=0 total=${#items[@]} key esc
  local selected=()
  for _ in "${items[@]}"; do selected+=(0); done

  hide_cursor
  echo -e "  ${BOLD}${prompt}${R}"
  echo -e "  ${DIM}(↑↓ navigate · Space toggle · Enter continue)${R}"
  echo ""

  _render_cb() {
    for i in "${!items[@]}"; do
      local box="[ ]" ocol="$DIM"
      [ "${selected[$i]}" -eq 1 ] && box="[${GR}x${R}]" && ocol=""
      if [ "$i" -eq "$cur" ]; then
        echo -e "  ${CY}${BOLD}▶${R}  ${box} ${BOLD}${items[$i]}${R}"
      else
        echo -e "     ${box} ${ocol}${items[$i]}${R}"
      fi
    done
  }

  printf '\033[s'
  _render_cb

  while true; do
    IFS= read -r -s -n1 key
    if [ "$key" = $'\x1b' ]; then
      IFS= read -r -s -n1 esc
      IFS= read -r -s -n1 esc
      case "$esc" in
        A) if [ "$cur" -gt 0 ]; then cur=$(( cur - 1 )); fi ;;
        B) if [ "$cur" -lt $(( total - 1 )) ]; then cur=$(( cur + 1 )); fi ;;
      esac
    elif [ "$key" = " " ]; then
      selected[$cur]=$(( 1 - selected[$cur] ))
    elif [ "$key" = "" ]; then
      break
    else
      continue
    fi
    printf '\033[u\033[0J'
    _render_cb
  done

  printf '\033[u\033[0J'
  show_cursor

  _checked=()
  for i in "${!items[@]}"; do
    [ "${selected[$i]}" -eq 1 ] && _checked+=("${items[$i]}")
  done

  if [ ${#_checked[@]} -gt 0 ]; then
    echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}"
    for item in "${_checked[@]}"; do echo -e "    ${CY}▸${R} ${item}"; done
  else
    echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}  ${DIM}(none — English only)${R}"
  fi
  echo ""
}

# ── TUI: text input ───────────────────────────────────────────────────────────
tui_input() {
  local -n _inp="$1"; shift
  local prompt="$1" default="${2:-}"
  printf '  '
  printf '%b' "${BOLD}"
  printf '%b' "$prompt"
  printf '%b' "${R}"
  if [ -n "$default" ]; then
    printf ' %b[%s]%b  ' "${DIM}" "$default" "${R}"
  else
    printf '  '
  fi
  IFS= read -r _inp
  [ -z "$_inp" ] && _inp="$default"
  echo ""
}

# ── TUI: masked password input ────────────────────────────────────────────────
tui_password() {
  local -n _pw="$1"; shift
  local prompt="$1" default="${2:-}"
  local _char _typed=""
  printf "  ${BOLD}%s${R} ${DIM}(hidden · enter = use default: %s)${R}  " "$prompt" "$default"
  while IFS= read -r -s -n1 _char; do
    if [ -z "$_char" ]; then
      break
    elif [ "$_char" = $'\x7f' ] || [ "$_char" = $'\b' ]; then
      if [ -n "$_typed" ]; then
        _typed="${_typed%?}"
        printf '\b \b'
      fi
    else
      _typed+="$_char"
      printf '*'
    fi
  done
  echo ""
  echo ""
  [ -z "$_typed" ] && _pw="$default" || _pw="$_typed"
}

# ── TUI: yes/no ───────────────────────────────────────────────────────────────
tui_yesno() {
  local -n _yn="$1"; shift
  local choice
  tui_select choice "$1" "Yes" "No"
  [ "$choice" = "Yes" ] && _yn=1 || _yn=0
}

# ═════════════════════════════════════════════════════════════════════════════
# Phase 0: Welcome
# ═════════════════════════════════════════════════════════════════════════════
phase_header "0" "Welcome"
echo -e "  This script will guide you through a full NixOS installation."
echo -e ""
echo -e "  ${YE}${BOLD}Requirements:${R}"
echo -e "    ${DIM}▸${R} Booted into a NixOS live ISO"
echo -e "    ${DIM}▸${R} Internet connection active"
echo -e "    ${DIM}▸${R} Target disk(s) visible under /dev/"
echo -e ""
read -r -s -p "  Press Enter to begin..." _
echo ""

# ═════════════════════════════════════════════════════════════════════════════
# Phase 1: System Identity
# ═════════════════════════════════════════════════════════════════════════════
phase_header "1" "System Identity"
echo -e "  Configure your username, config path, and login password."
echo ""

tui_input USERNAME "Username" "hogoshi"

_default_dest="/home/$USERNAME/nix-config"
tui_input DEST "Config path" "$_default_dest"

tui_password INIT_PASS "Initial password" "changeme"

echo -e "  ${GR}${BOLD}✓${R} Identity:"
echo -e "    ${DIM}▸${R} User:     ${CY}${USERNAME}${R}"
echo -e "    ${DIM}▸${R} Config:   ${CY}${DEST}${R}"
echo -e "    ${DIM}▸${R} Password: ${DIM}(set — hidden)${R}"
echo ""
read -r -s -p "  Press Enter to continue..." _
echo ""

# ═════════════════════════════════════════════════════════════════════════════
# Phase 2: Keyboard Layouts
# ═════════════════════════════════════════════════════════════════════════════
phase_header "2" "Keyboard Layouts"
echo -e "  ${GR}${BOLD}English (us)${R} is always included."
echo -e "  Select additional layouts. Cycle with ${CY}Alt+Shift${R}."
echo ""

_KB_OPTS=(
  "Russian    (ru)"
  "Spanish    (es)"
  "German     (de)"
  "French     (fr)"
  "Ukrainian  (ua)"
  "Polish     (pl)"
  "Japanese   (jp)"
  "Italian    (it)"
)

_KB_SELECTED=()
tui_checkbox _KB_SELECTED "Additional layouts:" "${_KB_OPTS[@]}"

KB_LAYOUT="us"
for _l in "${_KB_SELECTED[@]}"; do
  _code="${_l##*(}"
  _code="${_code%)}"
  _code="${_code// /}"
  KB_LAYOUT="${KB_LAYOUT},${_code}"
done

echo -e "  ${GR}${BOLD}✓${R} Active layout string:  ${CY}${BOLD}${KB_LAYOUT}${R}"
echo ""
read -r -s -p "  Press Enter to continue..." _
echo ""

# ═════════════════════════════════════════════════════════════════════════════
# Phase 3: Browser
# ═════════════════════════════════════════════════════════════════════════════
phase_header "3" "Browser"
echo -e "  Choose your default browser."
echo -e "  ${DIM}Zen Browser requires fetching from GitHub (github.com/youwen5/zen-browser-flake).${R}"
echo ""

tui_select BROWSER_CHOICE "Browser:" "Firefox" "Zen Browser"

# ═════════════════════════════════════════════════════════════════════════════
# Phase 4: Disks to Format
# ═════════════════════════════════════════════════════════════════════════════
phase_header "4" "Disks to Format"

mapfile -t ALL_DISKS < <(lsblk -dpno NAME,SIZE,MODEL \
  | grep -E '^/dev/(sd|nvme|vd)' \
  | awk '{printf "%s  (%s  %s)\n", $1, $2, $3}')

if [ ${#ALL_DISKS[@]} -eq 0 ]; then
  err "No disks detected. Is the system booted correctly?"
  show_cursor; exit 1
fi

FORMAT_DISKS=()
while [ ${#FORMAT_DISKS[@]} -eq 0 ]; do
  tui_checkbox FORMAT_DISKS "Select disks to format:" "${ALL_DISKS[@]}"
  if [ ${#FORMAT_DISKS[@]} -eq 0 ]; then
    warn "At least one disk must be selected."
  fi
done

# ═════════════════════════════════════════════════════════════════════════════
# Phase 5: Installation Disk
# ═════════════════════════════════════════════════════════════════════════════
phase_header "5" "Installation Disk"
echo -e "  ${DIM}Select which formatted disk NixOS will be installed on.${R}"
echo ""

PRIMARY_DISK=""
tui_select PRIMARY_DISK "Install NixOS on:" "${FORMAT_DISKS[@]}"
PRIMARY_DEV="${PRIMARY_DISK%% *}"

declare -A MOUNT_PATHS

for disk in "${FORMAT_DISKS[@]}"; do
  dev="${disk%% *}"
  [ "$dev" = "$PRIMARY_DEV" ] && continue
  mount_path=""
  tui_input mount_path "Mount path for ${CY}${dev}${R}:" "/hdd"
  MOUNT_PATHS["$dev"]="$mount_path"
done

# ═════════════════════════════════════════════════════════════════════════════
# Phase 6: Install Mode
# ═════════════════════════════════════════════════════════════════════════════
phase_header "6" "Install Mode"
echo -e "  ${BOLD}Auto${R}   — Script formats disk, runs nixos-install, sets everything up."
echo -e "  ${BOLD}Manual${R} — Script only writes config files; you run nixos-install yourself."
echo ""

INSTALL_MODE=""
tui_select INSTALL_MODE "How should NixOS be installed?" "Auto (fully automatic)" "Manual (I will run nixos-install myself)"

AUTO_INSTALL=0
[[ "$INSTALL_MODE" == Auto* ]] && AUTO_INSTALL=1

# ═════════════════════════════════════════════════════════════════════════════
# Phase 7: Write Nix configuration files
# ═════════════════════════════════════════════════════════════════════════════
phase_header "7" "Writing Configuration"

log "Creating ${DEST}..."
mkdir -p "$DEST"

log "Writing nix files..."
mkdir -p "$DEST"
cat > "$DEST/flake.nix" << 'NIX_EOF_flake_nix'
{
  description = "hogoshi's NixOS configuration";

  inputs = {
    millennium.url = "github:SteamClientHomebrew/Millennium?dir=packages/nix";

    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";

    home-manager = {
      url = "github:nix-community/home-manager";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    spicetify-nix = {
      url = "github:Gerg-L/spicetify-nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    zen-browser = {
      url = "github:youwen5/zen-browser-flake";
      inputs.nixpkgs.follows = "nixpkgs";
    };
  };

  outputs = inputs @ { self, nixpkgs, home-manager, spicetify-nix, ... }:
    let
      # true  = VPN only + minimal Hyprland (for initial setup behind Russia firewall)
      # false = full system (NVIDIA, apps, cachix, etc.)
      setupMode = true;

      # true = Zen Browser, false = Firefox
      useZen = false;

      system = "x86_64-linux";
    in {
      nixosConfigurations.nixos = nixpkgs.lib.nixosSystem {
        inherit system;
        specialArgs = { inherit inputs setupMode useZen; };
        modules = [
          ./hosts/configuration.nix
          home-manager.nixosModules.home-manager
          {
            home-manager.useGlobalPkgs    = true;
            home-manager.useUserPackages  = true;
            home-manager.extraSpecialArgs = { inherit inputs setupMode useZen; };
            home-manager.users.hogoshi    = import ./home;
          }
        ];
      };
    };
}
NIX_EOF_flake_nix

mkdir -p "$DEST/home"
cat > "$DEST/home/default.nix" << 'NIX_EOF_home_default_nix'
{ lib, setupMode, ... }: {
  imports = [
    ./programs/default.nix
  ] ++ lib.optionals (!setupMode) [
    ./programs/normal.nix
  ];

  home = {
    username      = "hogoshi";
    homeDirectory = "/home/hogoshi";
    stateVersion  = "24.11";
  };

  programs.home-manager.enable = true;
}
NIX_EOF_home_default_nix

mkdir -p "$DEST/home/programs/apps"
cat > "$DEST/home/programs/apps/default.nix" << 'NIX_EOF_home_programs_apps_default_nix'
{ pkgs, ... }: {
  home.packages = with pkgs; [
    htop
    git
    fastfetch
    kitty
  ];
}
NIX_EOF_home_programs_apps_default_nix

mkdir -p "$DEST/home/programs/apps"
cat > "$DEST/home/programs/apps/normal.nix" << 'NIX_EOF_home_programs_apps_normal_nix'
{ pkgs, ... }: {
  home.packages = with pkgs; [
    code-cursor
    telegram-desktop
    vesktop
    spotify
    pkgs.millennium-steam
  ];
}
NIX_EOF_home_programs_apps_normal_nix

mkdir -p "$DEST/home/programs"
cat > "$DEST/home/programs/bash.nix" << 'NIX_EOF_home_programs_bash_nix'
{ pkgs, lib, useZen, setupMode, ... }:
{
  programs.bash = {
    enable = true;
    profileExtra = ''
      if [ -z "$WAYLAND_DISPLAY" ] && [ "$XDG_VTNR" = "1" ]; then
        exec start-hyprland
      fi
    '';
    shellAliases = {
      rr    = "sudo nixos-rebuild switch --flake /etc/nixos#nixos";
      clear = "clear && fastfetch";
    };
    initExtra = ''
      ${lib.optionalString setupMode ''
        printf '\n  Setup keybindings:\n'
        printf '  Super+Enter  —  kitty\n'
        printf '  Super+F      —  ${if useZen then "zen" else "firefox"}\n'
        printf '  Super+K      —  throne\n\n'
      ''}
      fastfetch
      PS1='\[\e[38;5;117m\]\u:\[\e[0m\]\w\[\e[38;5;117m\]$ \[\e[0m\]'

      ww() {
        local json="$HOME/.cache/matugen/colors.json"
        if [ ! -f "$json" ]; then
          echo "ww: no matugen colors found at $json"
          return 1
        fi

        local kitty_colors="$HOME/.config/kitty/colors.conf"
        mkdir -p "$(dirname "$kitty_colors")"
        ${pkgs.jq}/bin/jq -r '
          .colors.dark |
          "background           " + .surface,
          "foreground           " + .on_surface,
          "selection_background " + .primary,
          "selection_foreground " + .on_primary,
          "cursor               " + .primary,
          "cursor_text_color    " + .on_primary,
          "color0  " + .surface,
          "color1  " + .error,
          "color2  " + .tertiary,
          "color3  " + .secondary,
          "color4  " + .primary,
          "color5  " + .tertiary_container,
          "color6  " + .secondary_container,
          "color7  " + .on_surface,
          "color8  " + .outline,
          "color9  " + .error_container,
          "color10 " + .on_tertiary,
          "color11 " + .on_secondary,
          "color12 " + .on_primary,
          "color13 " + .on_tertiary_container,
          "color14 " + .on_secondary_container,
          "color15 " + .surface_variant
        ' "$json" > "$kitty_colors"

        if [ -n "$KITTY_PID" ]; then
          kitty @ set-colors --all --configured "$kitty_colors" 2>/dev/null || true
        fi

        ${lib.optionalString useZen ''
        local zen_profile
        zen_profile=$(find "$HOME/.zen" -maxdepth 1 -name "*.default*" -type d 2>/dev/null | head -1)
        [ -z "$zen_profile" ] && zen_profile=$(find "$HOME/.zen" -maxdepth 1 -mindepth 1 -type d 2>/dev/null | head -1)
        if [ -n "$zen_profile" ]; then
          mkdir -p "$zen_profile/chrome"
          ${pkgs.jq}/bin/jq -r '
            .colors.dark |
            ":root {",
            "  --matugen-background: " + .surface + ";",
            "  --matugen-surface: " + .surface_variant + ";",
            "  --matugen-primary: " + .primary + ";",
            "  --matugen-on-primary: " + .on_primary + ";",
            "  --matugen-secondary: " + .secondary + ";",
            "  --matugen-on-surface: " + .on_surface + ";",
            "  --matugen-outline: " + .outline + ";",
            "  --matugen-error: " + .error + ";",
            "}"
          ' "$json" > "$zen_profile/chrome/matugen-vars.css"
        fi
        ''}
        ${lib.optionalString (!useZen) ''
        local ff_dir="$HOME/.mozilla/firefox/$USER/chrome"
        mkdir -p "$ff_dir"
        ${pkgs.jq}/bin/jq -r '
          .colors.dark |
          ":root {",
          "  --matugen-background: " + .surface + ";",
          "  --matugen-surface: " + .surface_variant + ";",
          "  --matugen-primary: " + .primary + ";",
          "  --matugen-on-primary: " + .on_primary + ";",
          "  --matugen-secondary: " + .secondary + ";",
          "  --matugen-on-surface: " + .on_surface + ";",
          "  --matugen-outline: " + .outline + ";",
          "  --matugen-error: " + .error + ";",
          "}"
        ' "$json" > "$ff_dir/matugen-vars.css"
        ''}

        local gtk_dir="$HOME/.config/gtk-3.0"
        mkdir -p "$gtk_dir"
        ${pkgs.jq}/bin/jq -r '
          .colors.dark |
          "@define-color accent_color " + .primary + ";",
          "@define-color accent_bg_color " + (.primary_container // .primary) + ";",
          "@define-color accent_fg_color " + .on_primary + ";",
          "@define-color destructive_color " + .error + ";",
          "@define-color window_bg_color " + .surface + ";",
          "@define-color window_fg_color " + .on_surface + ";",
          "@define-color view_bg_color " + .surface_variant + ";",
          "@define-color view_fg_color " + .on_surface + ";",
          "@define-color headerbar_bg_color " + .surface + ";",
          "@define-color headerbar_fg_color " + .on_surface + ";"
        ' "$json" > "$gtk_dir/gtk.css"

        echo "ww: colors synced from matugen"
      }
    '';
  };
}
NIX_EOF_home_programs_bash_nix

mkdir -p "$DEST/home/programs"
cat > "$DEST/home/programs/default.nix" << 'NIX_EOF_home_programs_default_nix'
{ lib, useZen, ... }: {
  imports = [
    ./bash.nix
    ./apps
    ./hyprland.nix
  ] ++ (if useZen then [ ./zen.nix ] else [ ./firefox.nix ]);
