log "Patching config for user: ${USERNAME}..."
find "$DEST" -name "*.nix" -print0 \
  | xargs -0 sed -i "s|hogoshi|${USERNAME}|g"
sed -i "s|initialPassword = \"[^\"]*\"|initialPassword = \"${INIT_PASS}\"|" \
  "$DEST/modules/system/users.nix"
if [ "$BROWSER_CHOICE" = "Zen Browser" ]; then
  sed -i "s|useZen = false|useZen = true|" "$DEST/flake.nix"
  log "Browser: Zen Browser (useZen = true)"
else
  log "Browser: Firefox (useZen = false)"
fi
if [ -f "$DEST/flake.lock" ]; then
  log "Removing flake.lock — sed/username edits change sources; locked self narHash would abort nixos-install."
  rm -f "$DEST/flake.lock"
fi
ok "Config patched."

log "Making ${DEST} readable/writable for all (no chown)..."
chmod -R a+rwX "$DEST" 2>/dev/null || warn "chmod a+rwX on ${DEST} incomplete (try as root if needed)"

log "Linking /etc/nixos → ${DEST}..."
if _capt "sudo ln /etc/nixos → ${DEST}" bash -c "sudo rm -rf /etc/nixos && sudo ln -sf \"$DEST\" /etc/nixos"; then
  ok "/etc/nixos linked."
else
  warn "Could not link /etc/nixos — do it manually: sudo ln -sf ${DEST} /etc/nixos"
fi

ok "Configuration written."

# ═════════════════════════════════════════════════════════════════════════════
# Phase 8: Disk Formatting
# ═════════════════════════════════════════════════════════════════════════════
phase_header "8" "Disk Formatting"

if [ -z "$PRIMARY_DEV" ]; then
  err "Installation disk was not selected."
  AUTO_INSTALL=0
fi

if [ "$AUTO_INSTALL" -eq 0 ]; then
  echo -e "  ${DIM}Manual mode — skipping disk formatting.${R}"
  echo ""
  if [ -n "$PRIMARY_DEV" ]; then
    echo -e "  Format ${CY}${PRIMARY_DEV}${R} yourself, then:"
  else
    echo -e "  Select and format your installation disk yourself, then:"
  fi
  echo -e "    ${BOLD}sudo nixos-generate-config --root /mnt${R}"
  echo -e "  ${DIM}With root on /mnt, copy your repo to /mnt/etc/nixos, then lock and install:${R}"
  echo -e "    ${BOLD}sudo cp -a /path/to/your-flake/. /mnt/etc/nixos/${R}"
  echo -e "    ${BOLD}sudo nix --extra-experimental-features 'nix-command flakes' flake lock /mnt/etc/nixos${R}"
  echo -e "    ${BOLD}sudo nixos-install --flake /mnt/etc/nixos#nixos${R}"
  echo -e "  ${DIM}(Using /home/... via /etc/nixos can trigger Nix flake narHash / store-path assertions.)${R}"
  read -r -s -p "  Press Enter to continue..." _
  echo ""
else
  echo -e "  ${YE}${BOLD}WARNING:${R} All data on ${CY}${BOLD}${PRIMARY_DEV}${R} will be destroyed."
  echo ""
  read -r -s -p "  Press Enter to confirm and begin formatting..." _
  echo ""

  log "Partitioning ${PRIMARY_DEV}..."
  if _capt "parted ${PRIMARY_DEV}" sudo parted -s "$PRIMARY_DEV" -- \
      mklabel gpt \
      mkpart ESP fat32 1MiB 512MiB \
      set 1 esp on \
      mkpart primary ext4 512MiB 100%; then
    ok "Partition table created."
  else
    err "Partitioning failed on ${PRIMARY_DEV}."
  fi

  if [[ "$PRIMARY_DEV" == *nvme* ]]; then
    BOOT_PART="${PRIMARY_DEV}p1"
    ROOT_PART="${PRIMARY_DEV}p2"
  else
    BOOT_PART="${PRIMARY_DEV}1"
    ROOT_PART="${PRIMARY_DEV}2"
  fi

  log "Formatting boot partition (FAT32)..."
  if _capt "mkfs.fat ${BOOT_PART}" sudo mkfs.fat -F 32 -n BOOT "$BOOT_PART"; then
    ok "Boot: ${BOOT_PART}"
  else
    warn "mkfs.fat failed on ${BOOT_PART}"
  fi

  log "Formatting root partition (ext4)..."
  if _capt "mkfs.ext4 ${ROOT_PART}" sudo mkfs.ext4 -L nixos "$ROOT_PART"; then
    ok "Root: ${ROOT_PART}"
  else
    warn "mkfs.ext4 failed on ${ROOT_PART}"
  fi

  log "Mounting root..."
  if _capt "mount ${ROOT_PART} /mnt" sudo mount "$ROOT_PART" /mnt; then
    ok "Mounted ${ROOT_PART} → /mnt"
  else
    err "Mount failed for ${ROOT_PART}"
  fi

  sudo mkdir -p /mnt/boot
  if _capt "mount ${BOOT_PART} /mnt/boot" sudo mount "$BOOT_PART" /mnt/boot; then
    ok "Mounted ${BOOT_PART} → /mnt/boot"
  else
    warn "Boot mount failed for ${BOOT_PART}"
  fi

  for dev in "${!MOUNT_PATHS[@]}"; do
    mpath="${MOUNT_PATHS[$dev]}"
    log "Formatting extra disk ${dev} (ext4)..."
    if _capt "mkfs.ext4 ${dev}" sudo mkfs.ext4 -L "$(basename "$mpath")" "$dev"; then
      ok "Formatted: ${dev}"
    else
      warn "mkfs.ext4 failed on ${dev}"
    fi
    sudo mkdir -p "/mnt${mpath}"
    if _capt "mount ${dev} → /mnt${mpath}" sudo mount "$dev" "/mnt${mpath}"; then
      ok "Mounted ${dev} → /mnt${mpath}"
    else
      warn "Could not mount ${dev} → /mnt${mpath}"
    fi
  done

  log "Generating hardware config..."
  if _capt "nixos-generate-config --root /mnt" sudo nixos-generate-config --root /mnt; then
    ok "hardware-configuration.nix generated."
  else
    warn "nixos-generate-config failed — hardware config may be incomplete"
  fi

  GENERATED_HW="/mnt/etc/nixos/hardware-configuration.nix"
  if [ -f "$GENERATED_HW" ]; then
    cp "$GENERATED_HW" "$DEST/hosts/hardware-configuration.nix"
    ok "Copied hardware config to repo."
  else
    warn "Could not find generated hardware-configuration.nix at ${GENERATED_HW}"
  fi
fi

# ═════════════════════════════════════════════════════════════════════════════
# Phase 9: NixOS Installation
# ═════════════════════════════════════════════════════════════════════════════
phase_header "9" "NixOS Installation"

if [ "$AUTO_INSTALL" -eq 0 ]; then
  echo -e "  ${DIM}Manual mode — skipping nixos-install.${R}"
  echo ""
  echo -e "  ${DIM}Copy your flake to /mnt/etc/nixos, then lock and install (avoids Nix flake.cc narHash assert):${R}"
  echo -e "    ${BOLD}sudo nix --extra-experimental-features 'nix-command flakes' flake lock /mnt/etc/nixos${R}"
  echo -e "    ${CY}${BOLD}sudo nixos-install --flake /mnt/etc/nixos#nixos${R}"
  echo -e "  ${DIM}Avoid /etc/nixos → /home/... when installing: Nix can abort on flake self narHash vs store path.${R}"
  read -r -s -p "  Press Enter to continue..." _
  echo ""
else
  log "Installing flake onto /mnt/etc/nixos (avoids /home + /etc/nixos symlink flake store assertions)..."
  sudo rm -rf /mnt/etc/nixos
  sudo mkdir -p /mnt/etc/nixos
  sudo cp -a "${DEST}/." /mnt/etc/nixos/
  sudo rm -f /mnt/etc/nixos/flake.lock
  sudo chmod -R a+rwX /mnt/etc/nixos 2>/dev/null || true
  log "Pointing live /etc/nixos → /mnt/etc/nixos so flake path matches target root..."
  if _capt "ln /etc/nixos → /mnt/etc/nixos" sudo ln -sfn /mnt/etc/nixos /etc/nixos; then
    ok "/etc/nixos → /mnt/etc/nixos"
  else
    warn "Could not relink /etc/nixos; install still uses /mnt/etc/nixos#nixos"
  fi
  log "Locking flake on target (fresh flake.lock; needs nix-command + flakes for root nix)..."
  if _capt "nix flake lock /mnt/etc/nixos" sudo nix --extra-experimental-features 'nix-command flakes' flake lock /mnt/etc/nixos; then
    ok "flake.lock written under /mnt/etc/nixos"
  else
    warn "nix flake lock failed (root nix needs flakes features, or network); nixos-install may still hit Nix flake.cc assertion"
  fi
  log "Running nixos-install..."
  echo ""
  _init_run_tmp
  _nil="$(mktemp "$RUN_TMP/nixinst.XXXXXX")"
  set +e
  set +o pipefail
  sudo nixos-install --no-root-passwd --flake /mnt/etc/nixos#nixos 2>&1 | tee "$_nil"
  _nix_ec=${PIPESTATUS[0]}
  set -o pipefail
  set -e
  if [ "$_nix_ec" -eq 0 ]; then
    rm -f "$_nil"
    ok "NixOS installed successfully."
    INSTALL_OK=1
  else
    err "nixos-install failed — captured output can be reviewed below."
    FAIL_DETAIL_LABELS+=("nixos-install")
    FAIL_DETAIL_FILES+=("$_nil")
  fi
fi

if [ "$AUTO_INSTALL" -eq 1 ] && [ "$INSTALL_OK" -eq 1 ]; then
phase_header "10" "Dotfiles & Assets"
log "Linking asset files..."
TARGET_ROOT="/mnt"
TARGET_CONFIG="/mnt/etc/nixos"
RUNTIME_CONFIG="/etc/nixos"
mkdir -p "$TARGET_CONFIG/assets"
cat > "$TARGET_CONFIG/assets/fastfetch.json" << 'ASSET_EOF_fastfetch_json_'
{
  "$schema": "https://github.com/fastfetch-cli/fastfetch/raw/dev/doc/json_schema.json",
  "logo": {
    "type": "builtin",
    "source": "nixos_small",
    "color": {
      "1": "blue",
      "2": "cyan"
    }
  },
  "display": {
    "separator": "  ",
    "color": {
      "keys": "blue",
      "title": "blue",
      "separator": "cyan"
    }
  },
  "modules": [
    "title",
    "separator",
    "os",
    "kernel",
    "uptime",
    "packages",
    "shell",
    "display",
    "de",
    "wm",
    "terminal",
    "cpu",
    "gpu",
    "memory",
    "disk",
    "separator",
    "colors"
  ]
}
ASSET_EOF_fastfetch_json_
_apath="/home/hogoshi/.config/fastfetch/config.json"
_apath="${_apath//hogoshi/$USERNAME}"
_target_apath="${TARGET_ROOT}${_apath}"
mkdir -p "$(dirname "$_target_apath")"
ln -sf "$RUNTIME_CONFIG/assets/fastfetch.json" "$_target_apath"
log "  linked: assets/fastfetch.json"

cat > "$TARGET_CONFIG/assets/hyprland.conf" << 'ASSET_EOF_hyprland_conf_'
source = ~/.local/share/ambxst/hyprland.conf

monitor = ,3440x1440@180,0x0,1

input {
    kb_layout = us
    kb_options = grp:alt_shift_toggle
}

misc {
    disable_autoreload = false
}
ASSET_EOF_hyprland_conf_
sed -i "s|kb_layout = .*|kb_layout = ${KB_LAYOUT}|" "$TARGET_CONFIG/assets/hyprland.conf"
log "  kb_layout → ${KB_LAYOUT}"
_apath="/home/hogoshi/.config/hypr/hyprland.conf"
_apath="${_apath//hogoshi/$USERNAME}"
_target_apath="${TARGET_ROOT}${_apath}"
mkdir -p "$(dirname "$_target_apath")"
ln -sf "$RUNTIME_CONFIG/assets/hyprland.conf" "$_target_apath"
log "  linked: assets/hyprland.conf"

fi

# ═════════════════════════════════════════════════════════════════════════════
# Phase 11: Done
# ═════════════════════════════════════════════════════════════════════════════
phase_header "11" "Complete"

nw=${#WARNINGS[@]}
nc=${#CRITICALS[@]}
nd=${#FAIL_DETAIL_LABELS[@]}

if [ "$nw" -eq 0 ] && [ "$nc" -eq 0 ]; then
  echo -e "  ${GR}${BOLD}All phases completed without errors.${R}"
else
  if [ "$nc" -gt 0 ]; then
    echo -e "  ${RE}${BOLD}Errors (${nc}):${R}"
    for e in "${CRITICALS[@]}"; do echo -e "    ${RE}▸${R} ${e}"; done
    echo ""
  fi
  if [ "$nw" -gt 0 ]; then
    echo -e "  ${YE}${BOLD}Warnings (${nw}):${R}"
    for e in "${WARNINGS[@]}"; do echo -e "    ${YE}▸${R} ${e}"; done
    echo ""
  fi
fi

echo ""
echo -e "  ${BOLD}Summary:${R}"
echo -e "    ${DIM}▸${R} User:     ${CY}${USERNAME}${R}"
if [ "$AUTO_INSTALL" -eq 1 ]; then
  echo -e "    ${DIM}▸${R} Config:   ${CY}/etc/nixos${R}"
else
  echo -e "    ${DIM}▸${R} Config:   ${CY}${DEST}${R}"
fi
echo -e "    ${DIM}▸${R} Keyboard: ${CY}${KB_LAYOUT}${R}"
echo -e "    ${DIM}▸${R} Browser:  ${CY}${BROWSER_CHOICE}${R}"
echo ""
if [ "$AUTO_INSTALL" -eq 0 ]; then
  echo -e "  ${BOLD}Manual next steps:${R}"
  echo -e "    ${DIM}1.${R} ${CY}sudo cp -a \"${DEST}/.\" /mnt/etc/nixos/${R}  ${DIM}·${R}  ${CY}sudo nix --extra-experimental-features 'nix-command flakes' flake lock /mnt/etc/nixos${R}"
  echo -e "    ${DIM}2.${R} ${CY}sudo nixos-install --flake /mnt/etc/nixos#nixos${R}"
  echo -e "    ${DIM}3.${R} Reboot:   ${CY}reboot${R}"
  echo -e "    ${DIM}4.${R} Login as: ${CY}${USERNAME}${R}  (password: ${CY}${INIT_PASS}${R})"
  echo -e "    ${DIM}5.${R} Set up VPN, edit flake → ${CY}setupMode = false${R}, run ${CY}rr${R}"
elif [ "$INSTALL_OK" -eq 1 ] && [ "$nw" -eq 0 ] && [ "$nc" -eq 0 ]; then
  echo -e "  ${GR}${BOLD}Auto install completed successfully.${R}"
  echo -e "  ${DIM}Rebooting in 5 seconds.${R}"
  sleep 5
  sudo reboot
else
  echo -e "  ${YE}${BOLD}Auto install did not finish cleanly. Reboot is not started.${R}"
fi
echo ""
if [ "$nw" -gt 0 ] || [ "$nc" -gt 0 ] || [ "$nd" -gt 0 ]; then
  _review_fail_logs
fi
